import { expect } from "chai"
import nock from "nock"
import { runCommand } from "@oclif/test"
import { cred } from "../../src/credentials"

describe("accounts:manage Data Test", function () {
    const testJson = {
        message: "Response from server",
    }

    const nockServerResponse = `{
  "message": "Response from server"
}`

    afterEach(() => {
        nock.cleanAll()
    })

    it("Test all required paramaters", async () => {
        nock("https://www.freeclimb.com")
            .post(`/apiserver/Accounts/${await cred.accountId}`, {})
            .query({})
            .reply(200, testJson)
        const { stdout } = await runCommand(["accounts:manage"])
        expect(stdout).to.contain(nockServerResponse)
    })

    it("Test Freeclimb Api error repsonce is process correctly without a suggestion", async () => {
        const testJsonErrorNoSuggestion = {
            code: 2,
            message: "Method Not Allowed",
            url: "https://docs.freeclimb.com/reference/error-and-warning-dictionary#2",
            details: {},
        }
        nock("https://www.freeclimb.com")
            .post(`/apiserver/Accounts/${await cred.accountId}`, {})
            .query({})
            .reply(500, testJsonErrorNoSuggestion)
        const { error } = await runCommand(["accounts:manage"])
        expect(error?.oclif?.exit).to.equal(3)
    })

    it("Sends API requests to the base URL from an environment variable", async () => {
        nock("https://user-custom-domain.example.com")
            .post(`/apiserver/Accounts/${await cred.accountId}`, {})
            .query({})
            .reply(200, testJson)
        const orig = process.env.FREECLIMB_CLI_BASE_URL
        process.env.FREECLIMB_CLI_BASE_URL = "https://user-custom-domain.example.com/apiserver"
        try {
            const { stdout } = await runCommand(["accounts:manage"])
            expect(stdout).to.contain(nockServerResponse)
        } finally {
            if (orig !== undefined) process.env.FREECLIMB_CLI_BASE_URL = orig
            else delete process.env.FREECLIMB_CLI_BASE_URL
        }
    })

    it("Test Freeclimb Api error repsonce is process correctly with a suggestion", async () => {
        const testJsonErrorWithSuggestion = {
            code: 50,
            message: "Unauthorized To Make Request",
            url: "https://docs.freeclimb.com/reference/error-and-warning-dictionary#50",
            details: {},
        }
        nock("https://www.freeclimb.com")
            .post(`/apiserver/Accounts/${await cred.accountId}`, {})
            .query({})
            .reply(500, testJsonErrorWithSuggestion)
        const { error } = await runCommand(["accounts:manage"])
        expect(error?.oclif?.exit).to.equal(3)
    })

    it("Test parse error gets triggered when there is an additional argument", async () => {
        const { error } = await runCommand(["accounts:manage", "additionalArguments"])
        expect(error?.oclif?.exit).to.equal(2)
    })

    it("Test error resulting in an unreadable response", async () => {
        nock("https://www.freeclimb.com")
            .post(`/apiserver/Accounts/${await cred.accountId}`, {})
            .query({})
            .reply(200, undefined)
        const { error } = await runCommand(["accounts:manage"])
        expect(error?.oclif?.exit).to.equal(3)
    })

    it("testing all body parameters together and required query are sent through with request", async () => {
        nock("https://www.freeclimb.com")
            .post(`/apiserver/Accounts/${await cred.accountId}`, {
                alias: "userInput-alias",
                label: "userInput-label",
            })
            .query({})
            .reply(200, testJson)
        const { stdout } = await runCommand([
            "accounts:manage",
            "--alias",
            "userInput-alias",
            "--label",
            "userInput-label",
        ])
        expect(stdout).to.contain(nockServerResponse)
    })

    describe("accounts:manage body param flags", function () {
        afterEach(() => {
            nock.cleanAll()
        })

        it("required params and a body param is sent through with request-alias", async () => {
            nock("https://www.freeclimb.com")
                .post(`/apiserver/Accounts/${await cred.accountId}`, {
                    alias: "userInput-alias",
                })
                .query({})
                .reply(200, testJson)
            const { stdout } = await runCommand(["accounts:manage", "--alias", "userInput-alias"])
            expect(stdout).to.contain(nockServerResponse)
        })

        it("required params and a body param is sent through with request-label", async () => {
            nock("https://www.freeclimb.com")
                .post(`/apiserver/Accounts/${await cred.accountId}`, {
                    label: "userInput-label",
                })
                .query({})
                .reply(200, testJson)
            const { stdout } = await runCommand(["accounts:manage", "--label", "userInput-label"])
            expect(stdout).to.contain(nockServerResponse)
        })
    })

    describe("accounts:manage next flag test", function () {
        afterEach(() => {
            nock.cleanAll()
        })

        it("Tests return of Exit Code 3 when flag next is not available", async () => {
            nock("https://www.freeclimb.com")
                .post(`/apiserver/Accounts/${await cred.accountId}`, {})
                .query({})
                .reply(200, testJson)
            const orig = process.env.FREECLIMB_ACCOUNTS_MANAGE_NEXT
            delete process.env.FREECLIMB_ACCOUNTS_MANAGE_NEXT
            try {
                await runCommand(["accounts:manage"])
                const { error } = await runCommand(["accounts:manage", "--next"])
                expect(error?.oclif?.exit).to.equal(3)
            } finally {
                if (orig !== undefined) process.env.FREECLIMB_ACCOUNTS_MANAGE_NEXT = orig
                else delete process.env.FREECLIMB_ACCOUNTS_MANAGE_NEXT
            }
        })
    })
})

